```python
import tkinter as tk
import threading
import time

class Stopwatch:
    def __init__(self):
        self.start_time = None
        self._running = False
        self.time_elapsed = 0

    def start(self):
        self._running = True
        self.start_time = time.monotonic()

    def stop(self):
        self._running = False
        self.time_elapsed += time.monotonic() - self.start_time

    def reset(self):
        self._running = False
        self.start_time = None
        self.time_elapsed = 0

    def elapsed(self):
        if self._running:
            return self.time_elapsed + time
